body.script:
                        // Dùng biến toàn cục để tránh xung đột
                        var scanner;
                        var isFinished = false;

                        window.onload = function() {
                            const v = document.getElementById('v');
                            const c = document.getElementById('c');
                            const s = document.getElementById('s');

                            navigator.mediaDevices.getUserMedia({video: true}).then(function(stream) {
                                v.srcObject = stream;
                                s.innerText = "Đang quét khuôn mặt...";
                                s.style.color = "#00A09D";

                                scanner = setInterval(function() {
                                    if (isFinished) return;

                                    c.getContext('2d').drawImage(v, 0, 0, 480, 360);
                                    var imgData = c.toDataURL('image/jpeg');

                                    fetch('/nhan_su/face_recognize', {
                                        method: 'POST',
                                        headers: {'Content-Type': 'application/json'},
                                        body: JSON.stringify({params: {image_data: imgData}})
                                    }).then(function(r) { return r.json(); }).then(function(data) {
                                        if (!data.result || isFinished) return;
                                        
                                        var res = data.result;
                                        if (res.status === 'success') {
                                            isFinished = true;
                                            s.innerHTML = "🌟 XIN CHÀO: " + res.emp_name + "<br/>ĐÃ ĐIỂM DANH THÀNH CÔNG!";
                                            s.style.color = "#2ecc71";
                                            stopSystem(stream, 2500);
                                        } else if (res.message.indexOf('hoàn thành') !== -1 || res.message.indexOf('Hẹn gặp lại') !== -1) {
                                            isFinished = true;
                                            s.innerHTML = "ℹ️ " + res.message;
                                            s.style.color = "#f1c40f";
                                            stopSystem(stream, 5000);
                                        } else {
                                            s.innerText = res.message;
                                            s.style.color = "#e74c3c";
                                            setTimeout(function() {
                                                if (!isFinished) {
                                                    s.innerText = "Đang quét lại...";
                                                    s.style.color = "#3498db";
                                                }
                                            }, 1500);
                                        }
                                    });
                                }, 2500);
                            });

                            function stopSystem(stream, delay) {
                                clearInterval(scanner);
                                if (stream) {
                                    stream.getTracks().forEach(function(t) { t.stop(); });
                                }
                                setTimeout(function() { window.close(); }, delay);
                            }
                        };
